class Solution:
    def longestDecomposition(self, text: str) -> int:
        def helper(s, start, end, count):
            if start >= end:
                return count
            for i in range(1, (end - start) // 2 + 1):
                if s[start:start + i] == s[end - i + 1:end + 1]:
                    return helper(s, start + i, end - i, count + 2)
            return helper(s, start + 1, end, count + 1)
        return helper(text, 0, len(text) - 1, 0)
